mapper.update:

update card
   set order_no=#{orderNo}, deck_no=#{deckNo}
 where no=#{no}

choose.when:

update card
   set order_no = order_no + 1
 where deck_no = #{deckNo}
   and order_no >= #{orderNo}

choose.otherwise:

update card
   set order_no = order_no - 1
 where deck_no = #{deckNo}
   and order_no > #{orderNo}
